// Normalizar y validar emails
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const seen = new Set();
const out = [];
for (const item of $input.all()) {
  const d = item.json;
  const email = String(d.email || '').trim().toLowerCase();
  if (!emailRegex.test(email) || seen.has(email)) continue;
  seen.add(email);
  out.push({
    json: {
      email,
      first_name: String(d.first_name || '').trim(),
      last_name: String(d.last_name || '').trim(),
      company: String(d.company || '').trim(),
      title: String(d.title || '').trim(),
      sector: String(d.sector || 'general').trim().toLowerCase(),
      source: 'csv_import'
    }
  });
}
return out;

// Filtrar emails que ya existen en DB o en supresión
const existing = new Set($('PG: Emails existentes').all().map(i => i.json.email));
return $('Code: Normalizar + Dedup interno').all().filter(i => !existing.has(i.json.email));

