// Parsear respuesta de Claude y combinar con datos del prospecto
const out = [];
const batchItems = $('Loop (10 por batch)').all();
const aiItems = $input.all();
for (let i = 0; i < aiItems.length; i++) {
  const prospect = batchItems[i].json;
  let ai = { lead_score: 50, sector: prospect.sector, notes: '' };
  try {
    const txt = aiItems[i].json.content[0].text.replace(/```json|```/g, '').trim();
    ai = JSON.parse(txt);
  } catch (e) { /* fallback a defaults */ }
  out.push({ json: { ...prospect, lead_score: ai.lead_score, sector: ai.sector || prospect.sector, notes: ai.notes || '' } });
}
return out;

